#!/bin/bashn# CSOS Build Script - Compiles codegen.csos and runs pipelinennset -ennSCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"nPROJECT_ROOT="$(dirname "$SCRIPT_DIR")"nnecho "=== CSOS Build System ==="necho "Project root: $PROJECT_ROOT"nn# Check for LLVMnif ! command -v clang++ &> /dev/null; thenn    echo "Error: clang++ not found. Install LLVM."n    exit 1nfinn# Compile codegennecho ">>> Compiling codegen..."nclang++ -std=c++20 -O3 -o "$PROJECT_ROOT/bin/csos_codegen" \n    "$PROJECT_ROOT/.opencode/tools/codegen.csos" \n    $(llvm-config --cxxflags --ldflags --system-libs --libs corejit orcjit) \n    -lpthread -ldlnnecho ">>> Compiling mermaid..."nclang++ -std=c++20 -O3 -o "$PROJECT_ROOT/bin/csos_mermaid" \n    "$PROJECT_ROOT/.opencode/tools/mermaid.csos" \n    -lpthreadnn# Ensure bin directory existsnmkdir -p "$PROJECT_ROOT/bin"nnecho "=== Build Complete ==="necho "Binaries: $PROJECT_ROOT/bin/csos_codegen"necho "           $PROJECT_ROOT/bin/csos_mermaid"n